/**
 * @summary Get analytics
 */
export const getGetAnalyticsUrl = (
  hotelId: number,
  params?: GetAnalyticsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/hotels/${hotelId}/analytics?${stringifiedParams}`
    : `/api/hotels/${hotelId}/analytics`;
};

export const getAnalytics = async (
  hotelId: number,
  params?: GetAnalyticsParams,
  options?: RequestInit,
): Promise<Analytics> => {
  return customFetch<Analytics>(getGetAnalyticsUrl(hotelId, params), {
    ...options,
    method: "GET",
  });
};

export const getGetAnalyticsQueryKey = (
  hotelId: number,
  params?: GetAnalyticsParams,
) => {
  return [
    `/api/hotels/${hotelId}/analytics`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetAnalyticsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAnalytics>>,
  TError = ErrorType<unknown>,
>(
  hotelId: number,
  params?: GetAnalyticsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAnalytics>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAnalyticsQueryKey(hotelId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getAnalytics>>> = ({
    signal,
  }) => getAnalytics(hotelId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!hotelId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getAnalytics>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAnalyticsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAnalytics>>
>;
export type GetAnalyticsQueryError = ErrorType<unknown>;

